// webgpu_host.rs — a wgpu-backed `navigator.gpu` for the monster runtime.
//
// include!d into gnexec.rs (shares its `Value`/`num`/anyhow scope) and compiled
// only under `--features webgpu`. WebGPU resources can't live in a serde_json
// Value, so each JS object is `{kind:"GPU<Type>", handle:N}` and N indexes a
// process-global registry holding the real wgpu objects. gnexec runs
// synchronously, so async WebGPU calls block here via pollster.
//
// Built test-by-test against a Deno oracle (open-source/gnosis/webgpu-compat).

// NB: this file is include!d into gnexec.rs, which already imports OnceLock/
// Mutex — fully-qualify here to avoid duplicate-import errors.

// A command encoder records high-level ops and materializes them at finish():
// wgpu's RenderPass borrows the encoder with a lifetime that can't survive
// across separate JS method calls, so we record and replay instead.
#[derive(Clone)]
enum PassCmd {
    SetPipeline(usize),
    SetVertexBuffer { slot: u32, buffer: usize },
    SetBindGroup { index: u32, group: usize },
    SetIndexBuffer { buffer: usize, u16: bool },
    Draw { vertices: u32, instances: u32 },
    DrawIndexed { indices: u32, instances: u32 },
}

#[derive(Clone)]
struct PassRec {
    view: usize,
    clear: [f64; 4],
    load_clear: bool,
    cmds: Vec<PassCmd>,
}

/// One recorded command inside a compute pass (replayed at encoder.finish()).
#[derive(Clone)]
enum ComputeCmd {
    SetPipeline(usize),
    SetBindGroup {
        index: u32,
        group: usize,
        dynamic_offsets: Vec<u32>,
    },
    Dispatch { x: u32, y: u32, z: u32 },
}

/// A recorded compute pass (mirrors PassRec for the render path).
#[derive(Clone)]
struct ComputePassRec {
    cmds: Vec<ComputeCmd>,
}

#[derive(Clone)]
enum EncCmd {
    Pass(PassRec),
    ComputePass(ComputePassRec),
    CopyTexToBuf {
        tex: usize,
        buffer: usize,
        bytes_per_row: u32,
        width: u32,
        height: u32,
    },
    CopyBufToBuf {
        src: usize,
        src_offset: u64,
        dst: usize,
        dst_offset: u64,
        size: u64,
    },
}

struct EncoderRec {
    device: usize,
    cmds: Vec<EncCmd>,
    open_pass: Option<usize>,
    /// index into `cmds` of the currently-open compute pass, if any.
    open_compute: Option<usize>,
}

struct GpuState {
    instance: wgpu::Instance,
    adapters: Vec<wgpu::Adapter>,
    devices: Vec<wgpu::Device>,
    queues: Vec<wgpu::Queue>,
    buffers: Vec<wgpu::Buffer>,
    /// device index that owns each buffer (for poll on mapAsync).
    buffer_device: Vec<usize>,
    /// bytes captured at mapAsync time, served by getMappedRange until unmap.
    mapped: std::collections::HashMap<usize, Vec<u8>>,
    shaders: Vec<wgpu::ShaderModule>,
    textures: Vec<wgpu::Texture>,
    views: Vec<wgpu::TextureView>,
    pipelines: Vec<wgpu::RenderPipeline>,
    compute_pipelines: Vec<wgpu::ComputePipeline>,
    bind_group_layouts: Vec<wgpu::BindGroupLayout>,
    pipeline_layouts: Vec<wgpu::PipelineLayout>,
    bind_groups: Vec<wgpu::BindGroup>,
    encoders: Vec<EncoderRec>,
    command_buffers: Vec<Option<wgpu::CommandBuffer>>,
}

fn gpu_state() -> &'static std::sync::Mutex<GpuState> {
    static GPU: std::sync::OnceLock<std::sync::Mutex<GpuState>> = std::sync::OnceLock::new();
    GPU.get_or_init(|| {
        std::sync::Mutex::new(GpuState {
            instance: wgpu::Instance::new(wgpu::InstanceDescriptor::default()),
            adapters: Vec::new(),
            devices: Vec::new(),
            queues: Vec::new(),
            buffers: Vec::new(),
            buffer_device: Vec::new(),
            mapped: std::collections::HashMap::new(),
            shaders: Vec::new(),
            textures: Vec::new(),
            views: Vec::new(),
            pipelines: Vec::new(),
            compute_pipelines: Vec::new(),
            bind_group_layouts: Vec::new(),
            pipeline_layouts: Vec::new(),
            bind_groups: Vec::new(),
            encoders: Vec::new(),
            command_buffers: Vec::new(),
        })
    })
}

/// Build a `{kind, handle}` JS handle object for a registry slot.
fn gpu_handle(kind: &str, handle: usize) -> Value {
    let mut m = serde_json::Map::new();
    m.insert("kind".into(), Value::String(kind.into()));
    m.insert("handle".into(), num(handle as f64));
    Value::Object(m)
}

fn handle_of(map: &serde_json::Map<String, Value>) -> usize {
    map.get("handle").and_then(Value::as_f64).unwrap_or(0.0) as usize
}

/// navigator.gpu.requestAdapter(options?) -> GPUAdapter
fn gpu_request_adapter(_args: &[Value]) -> anyhow::Result<Value> {
    let mut st = gpu_state().lock().unwrap();
    let adapter = pollster::block_on(st.instance.request_adapter(
        &wgpu::RequestAdapterOptions {
            power_preference: wgpu::PowerPreference::HighPerformance,
            compatible_surface: None,
            force_fallback_adapter: false,
        },
    ))
    .ok_or_else(|| anyhow::anyhow!("[webgpu] no adapter available"))?;
    let idx = st.adapters.len();
    st.adapters.push(adapter);
    Ok(gpu_handle("GPUAdapter", idx))
}

/// adapter.requestDevice(descriptor?) -> GPUDevice (with a `queue` handle)
fn gpu_request_device(
    recv: &serde_json::Map<String, Value>,
    _args: &[Value],
) -> anyhow::Result<Value> {
    let adapter_idx = handle_of(recv);
    let mut st = gpu_state().lock().unwrap();
    let (device, queue) = {
        let adapter = st
            .adapters
            .get(adapter_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad adapter handle"))?;
        // Compute needs real workgroup sizes + storage-buffer bindings, which
        // downlevel_defaults() under-provisions. The adapter's own advertised
        // limits are by definition supported, so request exactly those — this
        // unlocks full maxComputeWorkgroupSizeX/Y/Z, storage-buffer binding
        // counts, and large maxStorageBufferBindingSize for real inference.
        let required_limits = adapter.limits();
        pollster::block_on(adapter.request_device(
            &wgpu::DeviceDescriptor {
                label: Some("monster-webgpu"),
                required_features: wgpu::Features::empty(),
                required_limits,
            },
            None,
        ))?
    };
    let idx = st.devices.len();
    st.devices.push(device);
    st.queues.push(queue);

    let mut dev = serde_json::Map::new();
    dev.insert("kind".into(), Value::String("GPUDevice".into()));
    dev.insert("handle".into(), num(idx as f64));
    // The queue shares the device's registry index.
    dev.insert("queue".into(), gpu_handle("GPUQueue", idx));
    Ok(Value::Object(dev))
}

/// Read a JS number array (monster's representation of a Uint8Array) as bytes.
fn gpu_value_to_bytes(v: &Value) -> Vec<u8> {
    match v {
        Value::Array(a) => a.iter().map(|n| n.as_f64().unwrap_or(0.0) as u8).collect(),
        _ => Vec::new(),
    }
}

/// device.createBuffer({size, usage, mappedAtCreation?}) -> GPUBuffer
fn gpu_create_buffer(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let desc = args.first().and_then(|v| v.as_object());
    let size = desc
        .and_then(|d| d.get("size"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u64;
    let usage_bits = desc
        .and_then(|d| d.get("usage"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u32;
    let mapped_at_creation = desc
        .and_then(|d| d.get("mappedAtCreation"))
        .and_then(Value::as_bool)
        .unwrap_or(false);

    // Single lock: scope the immutable device borrow so the push reuses it.
    let mut st = gpu_state().lock().unwrap();
    let buffer = {
        let device = st
            .devices
            .get(device_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
        device.create_buffer(&wgpu::BufferDescriptor {
            label: None,
            size,
            usage: wgpu::BufferUsages::from_bits_truncate(usage_bits),
            mapped_at_creation,
        })
    };
    let idx = st.buffers.len();
    st.buffers.push(buffer);
    st.buffer_device.push(device_idx);

    let mut m = serde_json::Map::new();
    m.insert("kind".into(), Value::String("GPUBuffer".into()));
    m.insert("handle".into(), num(idx as f64));
    m.insert("size".into(), num(size as f64));
    Ok(Value::Object(m))
}

/// queue.writeBuffer(buffer, offset, data) — uploads bytes via the queue.
fn gpu_queue_write_buffer(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let queue_idx = handle_of(recv); // queue shares the device index
    let buffer_idx = args
        .first()
        .and_then(|v| v.as_object())
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] writeBuffer: bad buffer"))?;
    let offset = args.get(1).and_then(Value::as_f64).unwrap_or(0.0) as u64;
    let bytes = gpu_value_to_bytes(args.get(2).unwrap_or(&Value::Null));

    let st = gpu_state().lock().unwrap();
    let queue = st
        .queues
        .get(queue_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad queue handle"))?;
    let buffer = st
        .buffers
        .get(buffer_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad buffer handle"))?;
    queue.write_buffer(buffer, offset, &bytes);
    Ok(Value::Null)
}

/// buffer.mapAsync(mode) — maps, polls to completion, and captures the bytes so
/// getMappedRange can serve them. (Read-oriented; we copy then release.)
fn gpu_buffer_map_async(recv: &serde_json::Map<String, Value>) -> anyhow::Result<Value> {
    let buffer_idx = handle_of(recv);
    let st = gpu_state().lock().unwrap();
    let device_idx = *st
        .buffer_device
        .get(buffer_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad buffer handle"))?;
    let buffer = &st.buffers[buffer_idx];
    let device = &st.devices[device_idx];
    let slice = buffer.slice(..);
    slice.map_async(wgpu::MapMode::Read, |_| {});
    device.poll(wgpu::Maintain::Wait);
    let bytes = slice.get_mapped_range().to_vec();
    buffer.unmap();
    drop(st);

    gpu_state().lock().unwrap().mapped.insert(buffer_idx, bytes);
    Ok(Value::Null)
}

/// buffer.getMappedRange(offset?, size?) -> number[] (monster's Uint8Array).
fn gpu_buffer_get_mapped_range(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let buffer_idx = handle_of(recv);
    let st = gpu_state().lock().unwrap();
    let bytes = st
        .mapped
        .get(&buffer_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] getMappedRange before mapAsync"))?;
    let offset = args.first().and_then(Value::as_f64).unwrap_or(0.0) as usize;
    let size = args
        .get(1)
        .and_then(Value::as_f64)
        .map(|s| s as usize)
        .unwrap_or(bytes.len() - offset.min(bytes.len()));
    let end = (offset + size).min(bytes.len());
    let slice = &bytes[offset.min(bytes.len())..end];
    Ok(Value::Array(slice.iter().map(|&b| num(b as f64)).collect()))
}

fn gpu_buffer_unmap(recv: &serde_json::Map<String, Value>) -> anyhow::Result<Value> {
    let buffer_idx = handle_of(recv);
    gpu_state().lock().unwrap().mapped.remove(&buffer_idx);
    Ok(Value::Null)
}

/// GPUBufferUsage / GPUMapMode bit constants (identical to wgpu's bits).
fn gpu_buffer_usage_constants() -> Value {
    let mut m = serde_json::Map::new();
    for (k, v) in [
        ("MAP_READ", 0x1),
        ("MAP_WRITE", 0x2),
        ("COPY_SRC", 0x4),
        ("COPY_DST", 0x8),
        ("INDEX", 0x10),
        ("VERTEX", 0x20),
        ("UNIFORM", 0x40),
        ("STORAGE", 0x80),
        ("INDIRECT", 0x100),
        ("QUERY_RESOLVE", 0x200),
    ] {
        m.insert(k.into(), num(v as f64));
    }
    Value::Object(m)
}

fn gpu_map_mode_constants() -> Value {
    let mut m = serde_json::Map::new();
    m.insert("READ".into(), num(1.0));
    m.insert("WRITE".into(), num(2.0));
    Value::Object(m)
}

/// GPUShaderStage bit constants (identical to wgpu's ShaderStages bits).
fn gpu_shader_stage_constants() -> Value {
    let mut m = serde_json::Map::new();
    m.insert("VERTEX".into(), num(wgpu::ShaderStages::VERTEX.bits() as f64));
    m.insert(
        "FRAGMENT".into(),
        num(wgpu::ShaderStages::FRAGMENT.bits() as f64),
    );
    m.insert(
        "COMPUTE".into(),
        num(wgpu::ShaderStages::COMPUTE.bits() as f64),
    );
    Value::Object(m)
}

fn gpu_texture_usage_constants() -> Value {
    let mut m = serde_json::Map::new();
    for (k, v) in [
        ("COPY_SRC", 1),
        ("COPY_DST", 2),
        ("TEXTURE_BINDING", 4),
        ("STORAGE_BINDING", 8),
        ("RENDER_ATTACHMENT", 16),
    ] {
        m.insert(k.into(), num(v as f64));
    }
    Value::Object(m)
}

fn vertex_format(s: &str) -> wgpu::VertexFormat {
    match s {
        "float32" => wgpu::VertexFormat::Float32,
        "float32x2" => wgpu::VertexFormat::Float32x2,
        "float32x4" => wgpu::VertexFormat::Float32x4,
        "uint32" => wgpu::VertexFormat::Uint32,
        "uint32x2" => wgpu::VertexFormat::Uint32x2,
        "uint8x4" => wgpu::VertexFormat::Uint8x4,
        "unorm8x4" => wgpu::VertexFormat::Unorm8x4,
        _ => wgpu::VertexFormat::Float32x3,
    }
}

/// Owned vertex-buffer layout parsed from a pipeline descriptor (attributes are
/// kept alive separately so the wgpu::VertexBufferLayout can borrow them).
struct VblOwned {
    stride: u64,
    instance: bool,
    attrs: Vec<wgpu::VertexAttribute>,
}

fn parse_vertex_buffers(vtx: Option<&serde_json::Map<String, Value>>) -> Vec<VblOwned> {
    vtx.and_then(|v| v.get("buffers"))
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|b| b.as_object())
                .map(|b| VblOwned {
                    stride: b.get("arrayStride").and_then(Value::as_f64).unwrap_or(0.0) as u64,
                    instance: b
                        .get("stepMode")
                        .and_then(Value::as_str)
                        .map(|s| s == "instance")
                        .unwrap_or(false),
                    attrs: b
                        .get("attributes")
                        .and_then(|v| v.as_array())
                        .map(|aa| {
                            aa.iter()
                                .filter_map(|a| a.as_object())
                                .map(|a| wgpu::VertexAttribute {
                                    shader_location: a
                                        .get("shaderLocation")
                                        .and_then(Value::as_f64)
                                        .unwrap_or(0.0)
                                        as u32,
                                    offset: a.get("offset").and_then(Value::as_f64).unwrap_or(0.0)
                                        as u64,
                                    format: vertex_format(
                                        a.get("format").and_then(Value::as_str).unwrap_or("float32x3"),
                                    ),
                                })
                                .collect()
                        })
                        .unwrap_or_default(),
                })
                .collect()
        })
        .unwrap_or_default()
}

fn texture_format(s: &str) -> wgpu::TextureFormat {
    match s {
        "rgba8unorm-srgb" => wgpu::TextureFormat::Rgba8UnormSrgb,
        "bgra8unorm" => wgpu::TextureFormat::Bgra8Unorm,
        "bgra8unorm-srgb" => wgpu::TextureFormat::Bgra8UnormSrgb,
        "rgba16float" => wgpu::TextureFormat::Rgba16Float,
        "depth24plus" => wgpu::TextureFormat::Depth24Plus,
        "depth32float" => wgpu::TextureFormat::Depth32Float,
        _ => wgpu::TextureFormat::Rgba8Unorm,
    }
}

fn primitive_topology(s: &str) -> wgpu::PrimitiveTopology {
    match s {
        "point-list" => wgpu::PrimitiveTopology::PointList,
        "line-list" => wgpu::PrimitiveTopology::LineList,
        "line-strip" => wgpu::PrimitiveTopology::LineStrip,
        "triangle-strip" => wgpu::PrimitiveTopology::TriangleStrip,
        _ => wgpu::PrimitiveTopology::TriangleList,
    }
}

fn obj<'a>(v: Option<&'a Value>) -> Option<&'a serde_json::Map<String, Value>> {
    v.and_then(|v| v.as_object())
}

/// device.createShaderModule({code}) -> GPUShaderModule
fn gpu_create_shader_module(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let code = obj(args.first())
        .and_then(|d| d.get("code"))
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_string();
    let st = gpu_state().lock().unwrap();
    let device = st
        .devices
        .get(device_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
    let module = device.create_shader_module(wgpu::ShaderModuleDescriptor {
        label: None,
        source: wgpu::ShaderSource::Wgsl(code.into()),
    });
    drop(st);
    let mut st = gpu_state().lock().unwrap();
    let idx = st.shaders.len();
    st.shaders.push(module);
    Ok(gpu_handle("GPUShaderModule", idx))
}

/// device.createTexture({size, format, usage}) -> GPUTexture
fn gpu_create_texture(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let d = obj(args.first());
    let size = d.and_then(|d| d.get("size")).and_then(|v| v.as_object());
    let width = size
        .and_then(|s| s.get("width"))
        .and_then(Value::as_f64)
        .unwrap_or(1.0) as u32;
    let height = size
        .and_then(|s| s.get("height"))
        .and_then(Value::as_f64)
        .unwrap_or(1.0) as u32;
    let format = texture_format(
        d.and_then(|d| d.get("format"))
            .and_then(Value::as_str)
            .unwrap_or("rgba8unorm"),
    );
    let usage_bits = d
        .and_then(|d| d.get("usage"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u32;
    let st = gpu_state().lock().unwrap();
    let device = st
        .devices
        .get(device_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
    let tex = device.create_texture(&wgpu::TextureDescriptor {
        label: None,
        size: wgpu::Extent3d {
            width,
            height,
            depth_or_array_layers: 1,
        },
        mip_level_count: 1,
        sample_count: 1,
        dimension: wgpu::TextureDimension::D2,
        format,
        usage: wgpu::TextureUsages::from_bits_truncate(usage_bits),
        view_formats: &[],
    });
    drop(st);
    let mut st = gpu_state().lock().unwrap();
    let idx = st.textures.len();
    st.textures.push(tex);
    let mut m = serde_json::Map::new();
    m.insert("kind".into(), Value::String("GPUTexture".into()));
    m.insert("handle".into(), num(idx as f64));
    m.insert("width".into(), num(width as f64));
    m.insert("height".into(), num(height as f64));
    Ok(Value::Object(m))
}

/// texture.createView() -> GPUTextureView
fn gpu_texture_create_view(recv: &serde_json::Map<String, Value>) -> anyhow::Result<Value> {
    let tex_idx = handle_of(recv);
    let st = gpu_state().lock().unwrap();
    let tex = st
        .textures
        .get(tex_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad texture handle"))?;
    let view = tex.create_view(&wgpu::TextureViewDescriptor::default());
    drop(st);
    let mut st = gpu_state().lock().unwrap();
    let idx = st.views.len();
    st.views.push(view);
    Ok(gpu_handle("GPUTextureView", idx))
}

/// device.createRenderPipeline({layout, vertex, fragment, primitive}) (auto
/// layout / no vertex buffers for now — the triangle path).
fn gpu_create_render_pipeline(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let d = obj(args.first());
    let vtx = d.and_then(|d| d.get("vertex")).and_then(|v| v.as_object());
    let vtx_module = obj(vtx.and_then(|v| v.get("module")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] pipeline: no vertex module"))?;
    let vtx_entry = vtx
        .and_then(|v| v.get("entryPoint"))
        .and_then(Value::as_str)
        .unwrap_or("vs")
        .to_string();
    let frag = d.and_then(|d| d.get("fragment")).and_then(|v| v.as_object());
    let frag_module = obj(frag.and_then(|v| v.get("module"))).map(handle_of);
    let frag_entry = frag
        .and_then(|v| v.get("entryPoint"))
        .and_then(Value::as_str)
        .unwrap_or("fs")
        .to_string();
    let target_format = texture_format(
        frag.and_then(|v| v.get("targets"))
            .and_then(|v| v.as_array())
            .and_then(|a| a.first())
            .and_then(|t| t.as_object())
            .and_then(|t| t.get("format"))
            .and_then(Value::as_str)
            .unwrap_or("rgba8unorm"),
    );
    let topology = primitive_topology(
        d.and_then(|d| d.get("primitive"))
            .and_then(|v| v.as_object())
            .and_then(|p| p.get("topology"))
            .and_then(Value::as_str)
            .unwrap_or("triangle-list"),
    );

    let vbls = parse_vertex_buffers(vtx);

    let st = gpu_state().lock().unwrap();
    let device = st
        .devices
        .get(device_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
    let vmod = &st.shaders[vtx_module];
    let vb_layouts: Vec<wgpu::VertexBufferLayout> = vbls
        .iter()
        .map(|v| wgpu::VertexBufferLayout {
            array_stride: v.stride,
            step_mode: if v.instance {
                wgpu::VertexStepMode::Instance
            } else {
                wgpu::VertexStepMode::Vertex
            },
            attributes: &v.attrs,
        })
        .collect();
    let targets = [Some(wgpu::ColorTargetState {
        format: target_format,
        blend: Some(wgpu::BlendState::ALPHA_BLENDING),
        write_mask: wgpu::ColorWrites::ALL,
    })];
    let fmod = frag_module.map(|i| &st.shaders[i]);
    let pipeline = device.create_render_pipeline(&wgpu::RenderPipelineDescriptor {
        label: None,
        layout: None,
        vertex: wgpu::VertexState {
            module: vmod,
            entry_point: &vtx_entry,
            buffers: &vb_layouts,
            compilation_options: Default::default(),
        },
        fragment: fmod.map(|fm| wgpu::FragmentState {
            module: fm,
            entry_point: &frag_entry,
            targets: &targets,
            compilation_options: Default::default(),
        }),
        primitive: wgpu::PrimitiveState {
            topology,
            ..Default::default()
        },
        depth_stencil: None,
        multisample: wgpu::MultisampleState::default(),
        multiview: None,
    });
    drop(st);
    let mut st = gpu_state().lock().unwrap();
    let idx = st.pipelines.len();
    st.pipelines.push(pipeline);
    Ok(gpu_handle("GPURenderPipeline", idx))
}

// ──────────────────────────────── compute ──────────────────────────────────
//
// The compute path mirrors the render path on the same registry: a WGSL module
// + entryPoint + ('auto' | explicit) layout becomes a GPUComputePipeline; a
// GPUCommandEncoder opens a recorded ComputePass; setPipeline/setBindGroup/
// dispatchWorkgroups are replayed at encoder.finish(); storage-buffer outputs
// read back via copyBufferToBuffer into a MAP_READ staging buffer.

/// Parse a WGSL buffer binding type string into wgpu's BufferBindingType.
fn buffer_binding_type(s: &str) -> wgpu::BufferBindingType {
    match s {
        "uniform" => wgpu::BufferBindingType::Uniform,
        "read-only-storage" => wgpu::BufferBindingType::Storage { read_only: true },
        // default + "storage" → read-write storage.
        _ => wgpu::BufferBindingType::Storage { read_only: false },
    }
}

/// device.createBindGroupLayout({entries:[{binding,visibility,buffer:{type}}]})
fn gpu_create_bind_group_layout(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let entries: Vec<wgpu::BindGroupLayoutEntry> = obj(args.first())
        .and_then(|d| d.get("entries"))
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|e| e.as_object())
                .map(|e| {
                    let binding =
                        e.get("binding").and_then(Value::as_f64).unwrap_or(0.0) as u32;
                    let vis_bits = e
                        .get("visibility")
                        .and_then(Value::as_f64)
                        .unwrap_or(wgpu::ShaderStages::COMPUTE.bits() as f64)
                        as u32;
                    let buf = e.get("buffer").and_then(|v| v.as_object());
                    let ty = buffer_binding_type(
                        buf.and_then(|b| b.get("type"))
                            .and_then(Value::as_str)
                            .unwrap_or("storage"),
                    );
                    let has_dynamic_offset = buf
                        .and_then(|b| b.get("hasDynamicOffset"))
                        .and_then(Value::as_bool)
                        .unwrap_or(false);
                    wgpu::BindGroupLayoutEntry {
                        binding,
                        visibility: wgpu::ShaderStages::from_bits_truncate(vis_bits),
                        ty: wgpu::BindingType::Buffer {
                            ty,
                            has_dynamic_offset,
                            min_binding_size: None,
                        },
                        count: None,
                    }
                })
                .collect()
        })
        .unwrap_or_default();
    let mut st = gpu_state().lock().unwrap();
    let layout = {
        let device = st
            .devices
            .get(device_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
        device.create_bind_group_layout(&wgpu::BindGroupLayoutDescriptor {
            label: None,
            entries: &entries,
        })
    };
    let idx = st.bind_group_layouts.len();
    st.bind_group_layouts.push(layout);
    Ok(gpu_handle("GPUBindGroupLayout", idx))
}

/// device.createPipelineLayout({bindGroupLayouts:[GPUBindGroupLayout]})
fn gpu_create_pipeline_layout(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let bgl_indices: Vec<usize> = obj(args.first())
        .and_then(|d| d.get("bindGroupLayouts"))
        .and_then(|v| v.as_array())
        .map(|a| a.iter().filter_map(|v| v.as_object()).map(handle_of).collect())
        .unwrap_or_default();
    let mut st = gpu_state().lock().unwrap();
    let layout = {
        let bgls: Vec<&wgpu::BindGroupLayout> =
            bgl_indices.iter().map(|&i| &st.bind_group_layouts[i]).collect();
        let device = st
            .devices
            .get(device_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
        device.create_pipeline_layout(&wgpu::PipelineLayoutDescriptor {
            label: None,
            bind_group_layouts: &bgls,
            push_constant_ranges: &[],
        })
    };
    let idx = st.pipeline_layouts.len();
    st.pipeline_layouts.push(layout);
    Ok(gpu_handle("GPUPipelineLayout", idx))
}

/// device.createComputePipeline({layout, compute:{module, entryPoint}})
/// layout is 'auto' (a string) or an explicit GPUPipelineLayout handle.
fn gpu_create_compute_pipeline(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let d = obj(args.first());
    let comp = d.and_then(|d| d.get("compute")).and_then(|v| v.as_object());
    let module_idx = obj(comp.and_then(|c| c.get("module")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] compute pipeline: no module"))?;
    let entry = comp
        .and_then(|c| c.get("entryPoint"))
        .and_then(Value::as_str)
        .unwrap_or("main")
        .to_string();
    // layout: 'auto' string → None; otherwise a GPUPipelineLayout handle.
    let explicit_layout = d
        .and_then(|d| d.get("layout"))
        .and_then(|v| v.as_object())
        .map(handle_of);

    let mut st = gpu_state().lock().unwrap();
    let pipeline = {
        let device = st
            .devices
            .get(device_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
        let module = &st.shaders[module_idx];
        let layout_ref = explicit_layout.map(|i| &st.pipeline_layouts[i]);
        device.create_compute_pipeline(&wgpu::ComputePipelineDescriptor {
            label: None,
            layout: layout_ref,
            module,
            entry_point: &entry,
            compilation_options: Default::default(),
        })
    };
    let idx = st.compute_pipelines.len();
    st.compute_pipelines.push(pipeline);
    Ok(gpu_handle("GPUComputePipeline", idx))
}

/// pipeline.getBindGroupLayout(group) — auto-layout pipelines mint their bind
/// group layouts from the WGSL; reflect group N into a GPUBindGroupLayout
/// handle so createBindGroup can reference it.
fn gpu_pipeline_get_bind_group_layout(
    kind: &str,
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let pipe_idx = handle_of(recv);
    let group = args.first().and_then(Value::as_f64).unwrap_or(0.0) as u32;
    let mut st = gpu_state().lock().unwrap();
    let layout = if kind == "GPUComputePipeline" {
        st.compute_pipelines[pipe_idx].get_bind_group_layout(group)
    } else {
        st.pipelines[pipe_idx].get_bind_group_layout(group)
    };
    let idx = st.bind_group_layouts.len();
    st.bind_group_layouts.push(layout);
    Ok(gpu_handle("GPUBindGroupLayout", idx))
}

/// device.createBindGroup({layout, entries:[{binding, resource:{buffer,offset?,size?}}]})
fn gpu_create_bind_group(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let d = obj(args.first());
    let layout_idx = obj(d.and_then(|d| d.get("layout")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bind group: no layout"))?;
    // Parse entries into (binding, buffer_idx, offset, size?) tuples up front.
    struct EntrySpec {
        binding: u32,
        buffer: usize,
        offset: u64,
        size: Option<u64>,
    }
    let specs: Vec<EntrySpec> = d
        .and_then(|d| d.get("entries"))
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|e| e.as_object())
                .filter_map(|e| {
                    let binding = e.get("binding").and_then(Value::as_f64)? as u32;
                    let res = e.get("resource").and_then(|v| v.as_object())?;
                    let buffer = obj(res.get("buffer")).map(handle_of)?;
                    let offset =
                        res.get("offset").and_then(Value::as_f64).unwrap_or(0.0) as u64;
                    let size = res.get("size").and_then(Value::as_f64).map(|s| s as u64);
                    Some(EntrySpec {
                        binding,
                        buffer,
                        offset,
                        size,
                    })
                })
                .collect()
        })
        .unwrap_or_default();

    let mut st = gpu_state().lock().unwrap();
    let bind_group = {
        let entries: Vec<wgpu::BindGroupEntry> = specs
            .iter()
            .map(|s| wgpu::BindGroupEntry {
                binding: s.binding,
                resource: wgpu::BindingResource::Buffer(wgpu::BufferBinding {
                    buffer: &st.buffers[s.buffer],
                    offset: s.offset,
                    size: s.size.and_then(std::num::NonZeroU64::new),
                }),
            })
            .collect();
        let layout = &st.bind_group_layouts[layout_idx];
        let device = st
            .devices
            .get(device_idx)
            .ok_or_else(|| anyhow::anyhow!("[webgpu] bad device handle"))?;
        device.create_bind_group(&wgpu::BindGroupDescriptor {
            label: None,
            layout,
            entries: &entries,
        })
    };
    let idx = st.bind_groups.len();
    st.bind_groups.push(bind_group);
    Ok(gpu_handle("GPUBindGroup", idx))
}

/// encoder.beginComputePass(descriptor?) -> GPUComputePassEncoder
fn gpu_encoder_begin_compute_pass(
    recv: &serde_json::Map<String, Value>,
) -> anyhow::Result<Value> {
    let enc_idx = handle_of(recv);
    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    let pass_idx = enc.cmds.len();
    enc.cmds.push(EncCmd::ComputePass(ComputePassRec { cmds: Vec::new() }));
    enc.open_compute = Some(pass_idx);
    Ok(gpu_handle("GPUComputePassEncoder", enc_idx))
}

/// Append a command into the encoder's currently-open compute pass.
fn compute_pass_push(enc_idx: usize, cmd: ComputeCmd) -> anyhow::Result<Value> {
    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    let p = enc
        .open_compute
        .ok_or_else(|| anyhow::anyhow!("[webgpu] no open compute pass"))?;
    if let EncCmd::ComputePass(ref mut cp) = enc.cmds[p] {
        cp.cmds.push(cmd);
    }
    Ok(Value::Null)
}

/// encoder.copyBufferToBuffer(src, srcOffset, dst, dstOffset, size)
fn gpu_encoder_copy_buffer_to_buffer(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let enc_idx = handle_of(recv);
    let src = obj(args.first())
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] copyBufferToBuffer: no src"))?;
    let src_offset = args.get(1).and_then(Value::as_f64).unwrap_or(0.0) as u64;
    let dst = obj(args.get(2))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] copyBufferToBuffer: no dst"))?;
    let dst_offset = args.get(3).and_then(Value::as_f64).unwrap_or(0.0) as u64;
    let size = args.get(4).and_then(Value::as_f64).unwrap_or(0.0) as u64;
    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    enc.cmds.push(EncCmd::CopyBufToBuf {
        src,
        src_offset,
        dst,
        dst_offset,
        size,
    });
    Ok(Value::Null)
}

fn gpu_create_command_encoder(recv: &serde_json::Map<String, Value>) -> anyhow::Result<Value> {
    let device_idx = handle_of(recv);
    let mut st = gpu_state().lock().unwrap();
    let idx = st.encoders.len();
    st.encoders.push(EncoderRec {
        device: device_idx,
        cmds: Vec::new(),
        open_pass: None,
        open_compute: None,
    });
    Ok(gpu_handle("GPUCommandEncoder", idx))
}

fn gpu_encoder_begin_render_pass(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let enc_idx = handle_of(recv);
    let ca = obj(args.first())
        .and_then(|d| d.get("colorAttachments"))
        .and_then(|v| v.as_array())
        .and_then(|a| a.first())
        .and_then(|v| v.as_object());
    let view_idx = obj(ca.and_then(|c| c.get("view")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] render pass: no view"))?;
    let load_clear = ca
        .and_then(|c| c.get("loadOp"))
        .and_then(Value::as_str)
        .map(|s| s == "clear")
        .unwrap_or(true);
    let cv = obj(ca.and_then(|c| c.get("clearValue")));
    let g = |k: &str, def: f64| cv.and_then(|c| c.get(k)).and_then(Value::as_f64).unwrap_or(def);
    let clear = [g("r", 0.0), g("g", 0.0), g("b", 0.0), g("a", 1.0)];

    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    let pass_idx = enc.cmds.len();
    enc.cmds.push(EncCmd::Pass(PassRec {
        view: view_idx,
        clear,
        load_clear,
        cmds: Vec::new(),
    }));
    enc.open_pass = Some(pass_idx);
    Ok(gpu_handle("GPURenderPassEncoder", enc_idx))
}

fn pass_push(enc_idx: usize, cmd: PassCmd) -> anyhow::Result<Value> {
    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    let p = enc
        .open_pass
        .ok_or_else(|| anyhow::anyhow!("[webgpu] no open render pass"))?;
    if let EncCmd::Pass(ref mut pr) = enc.cmds[p] {
        pr.cmds.push(cmd);
    }
    Ok(Value::Null)
}

fn gpu_encoder_copy_texture_to_buffer(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let enc_idx = handle_of(recv);
    let tex = obj(obj(args.first()).and_then(|s| s.get("texture")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] copy: no texture"))?;
    let dst = obj(args.get(1));
    let buffer = obj(dst.and_then(|d| d.get("buffer")))
        .map(handle_of)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] copy: no buffer"))?;
    let bytes_per_row = dst
        .and_then(|d| d.get("bytesPerRow"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u32;
    let size = obj(args.get(2));
    let width = size
        .and_then(|s| s.get("width"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u32;
    let height = size
        .and_then(|s| s.get("height"))
        .and_then(Value::as_f64)
        .unwrap_or(0.0) as u32;
    let mut st = gpu_state().lock().unwrap();
    let enc = st
        .encoders
        .get_mut(enc_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad encoder handle"))?;
    enc.cmds.push(EncCmd::CopyTexToBuf {
        tex,
        buffer,
        bytes_per_row,
        width,
        height,
    });
    Ok(Value::Null)
}

/// encoder.finish() — materialize recorded ops into a wgpu CommandBuffer.
fn gpu_encoder_finish(recv: &serde_json::Map<String, Value>) -> anyhow::Result<Value> {
    let enc_idx = handle_of(recv);
    let mut st = gpu_state().lock().unwrap();
    let device_idx = st.encoders[enc_idx].device;
    let cmds = std::mem::take(&mut st.encoders[enc_idx].cmds);
    let mut wenc = st.devices[device_idx]
        .create_command_encoder(&wgpu::CommandEncoderDescriptor { label: None });
    for cmd in &cmds {
        match cmd {
            EncCmd::Pass(p) => {
                let load = if p.load_clear {
                    wgpu::LoadOp::Clear(wgpu::Color {
                        r: p.clear[0],
                        g: p.clear[1],
                        b: p.clear[2],
                        a: p.clear[3],
                    })
                } else {
                    wgpu::LoadOp::Load
                };
                let mut rp = wenc.begin_render_pass(&wgpu::RenderPassDescriptor {
                    label: None,
                    color_attachments: &[Some(wgpu::RenderPassColorAttachment {
                        view: &st.views[p.view],
                        resolve_target: None,
                        ops: wgpu::Operations {
                            load,
                            store: wgpu::StoreOp::Store,
                        },
                    })],
                    depth_stencil_attachment: None,
                    timestamp_writes: None,
                    occlusion_query_set: None,
                });
                for pc in &p.cmds {
                    match pc {
                        PassCmd::SetPipeline(i) => rp.set_pipeline(&st.pipelines[*i]),
                        PassCmd::SetVertexBuffer { slot, buffer } => {
                            rp.set_vertex_buffer(*slot, st.buffers[*buffer].slice(..))
                        }
                        PassCmd::SetBindGroup { .. } => {}
                        PassCmd::SetIndexBuffer { buffer, u16 } => rp.set_index_buffer(
                            st.buffers[*buffer].slice(..),
                            if *u16 {
                                wgpu::IndexFormat::Uint16
                            } else {
                                wgpu::IndexFormat::Uint32
                            },
                        ),
                        PassCmd::Draw {
                            vertices,
                            instances,
                        } => rp.draw(0..*vertices, 0..*instances),
                        PassCmd::DrawIndexed { indices, instances } => {
                            rp.draw_indexed(0..*indices, 0, 0..*instances)
                        }
                    }
                }
            }
            EncCmd::CopyTexToBuf {
                tex,
                buffer,
                bytes_per_row,
                width,
                height,
            } => {
                wenc.copy_texture_to_buffer(
                    wgpu::ImageCopyTexture {
                        texture: &st.textures[*tex],
                        mip_level: 0,
                        origin: wgpu::Origin3d::ZERO,
                        aspect: wgpu::TextureAspect::All,
                    },
                    wgpu::ImageCopyBuffer {
                        buffer: &st.buffers[*buffer],
                        layout: wgpu::ImageDataLayout {
                            offset: 0,
                            bytes_per_row: Some(*bytes_per_row),
                            rows_per_image: Some(*height),
                        },
                    },
                    wgpu::Extent3d {
                        width: *width,
                        height: *height,
                        depth_or_array_layers: 1,
                    },
                );
            }
            EncCmd::ComputePass(cp) => {
                let mut pass =
                    wenc.begin_compute_pass(&wgpu::ComputePassDescriptor {
                        label: None,
                        timestamp_writes: None,
                    });
                for cc in &cp.cmds {
                    match cc {
                        ComputeCmd::SetPipeline(i) => {
                            pass.set_pipeline(&st.compute_pipelines[*i])
                        }
                        ComputeCmd::SetBindGroup {
                            index,
                            group,
                            dynamic_offsets,
                        } => pass.set_bind_group(
                            *index,
                            &st.bind_groups[*group],
                            dynamic_offsets,
                        ),
                        ComputeCmd::Dispatch { x, y, z } => {
                            pass.dispatch_workgroups(*x, *y, *z)
                        }
                    }
                }
            }
            EncCmd::CopyBufToBuf {
                src,
                src_offset,
                dst,
                dst_offset,
                size,
            } => {
                wenc.copy_buffer_to_buffer(
                    &st.buffers[*src],
                    *src_offset,
                    &st.buffers[*dst],
                    *dst_offset,
                    *size,
                );
            }
        }
    }
    let cb = wenc.finish();
    let idx = st.command_buffers.len();
    st.command_buffers.push(Some(cb));
    Ok(gpu_handle("GPUCommandBuffer", idx))
}

fn gpu_queue_submit(
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> anyhow::Result<Value> {
    let queue_idx = handle_of(recv);
    let cb_indices: Vec<usize> = args
        .first()
        .and_then(|v| v.as_array())
        .map(|a| a.iter().filter_map(|v| v.as_object()).map(handle_of).collect())
        .unwrap_or_default();
    let mut st = gpu_state().lock().unwrap();
    let mut cbs = Vec::new();
    for i in cb_indices {
        if let Some(cb) = st.command_buffers.get_mut(i).and_then(|o| o.take()) {
            cbs.push(cb);
        }
    }
    let queue = st
        .queues
        .get(queue_idx)
        .ok_or_else(|| anyhow::anyhow!("[webgpu] bad queue handle"))?;
    queue.submit(cbs);
    Ok(Value::Null)
}

/// Dispatch a method call on a `{kind:"GPU*"}` handle object. Returns
/// `Some(result)` when handled, `None` to fall through to the default path.
fn gpu_dispatch(
    kind: &str,
    method: &str,
    recv: &serde_json::Map<String, Value>,
    args: &[Value],
) -> Option<anyhow::Result<Value>> {
    let u32a = |i: usize, def: u32| args.get(i).and_then(Value::as_f64).map(|f| f as u32).unwrap_or(def);
    match (kind, method) {
        ("GPUObject", "requestAdapter") => Some(gpu_request_adapter(args)),
        ("GPUAdapter", "requestDevice") => Some(gpu_request_device(recv, args)),
        ("GPUDevice", "createBuffer") => Some(gpu_create_buffer(recv, args)),
        ("GPUDevice", "createShaderModule") => Some(gpu_create_shader_module(recv, args)),
        ("GPUDevice", "createTexture") => Some(gpu_create_texture(recv, args)),
        ("GPUDevice", "createRenderPipeline") => Some(gpu_create_render_pipeline(recv, args)),
        ("GPUDevice", "createComputePipeline") => Some(gpu_create_compute_pipeline(recv, args)),
        ("GPUDevice", "createBindGroupLayout") => Some(gpu_create_bind_group_layout(recv, args)),
        ("GPUDevice", "createPipelineLayout") => Some(gpu_create_pipeline_layout(recv, args)),
        ("GPUDevice", "createBindGroup") => Some(gpu_create_bind_group(recv, args)),
        ("GPUDevice", "createCommandEncoder") => Some(gpu_create_command_encoder(recv)),
        ("GPUComputePipeline", "getBindGroupLayout")
        | ("GPURenderPipeline", "getBindGroupLayout") => {
            Some(gpu_pipeline_get_bind_group_layout(kind, recv, args))
        }
        ("GPUTexture", "createView") => Some(gpu_texture_create_view(recv)),
        ("GPUQueue", "writeBuffer") => Some(gpu_queue_write_buffer(recv, args)),
        ("GPUQueue", "submit") => Some(gpu_queue_submit(recv, args)),
        ("GPUBuffer", "mapAsync") => Some(gpu_buffer_map_async(recv)),
        ("GPUBuffer", "getMappedRange") => Some(gpu_buffer_get_mapped_range(recv, args)),
        ("GPUBuffer", "unmap") => Some(gpu_buffer_unmap(recv)),
        ("GPUCommandEncoder", "beginRenderPass") => Some(gpu_encoder_begin_render_pass(recv, args)),
        ("GPUCommandEncoder", "beginComputePass") => {
            Some(gpu_encoder_begin_compute_pass(recv))
        }
        ("GPUCommandEncoder", "copyTextureToBuffer") => {
            Some(gpu_encoder_copy_texture_to_buffer(recv, args))
        }
        ("GPUCommandEncoder", "copyBufferToBuffer") => {
            Some(gpu_encoder_copy_buffer_to_buffer(recv, args))
        }
        ("GPUCommandEncoder", "finish") => Some(gpu_encoder_finish(recv)),
        ("GPUComputePassEncoder", "setPipeline") => Some(
            obj(args.first())
                .map(handle_of)
                .map(|p| compute_pass_push(handle_of(recv), ComputeCmd::SetPipeline(p)))
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPUComputePassEncoder", "setBindGroup") => Some(
            obj(args.get(1))
                .map(handle_of)
                .map(|gidx| {
                    // dynamicOffsets (arg 2) is an optional number[] passed by value.
                    let dynamic_offsets: Vec<u32> = args
                        .get(2)
                        .and_then(|v| v.as_array())
                        .map(|a| {
                            a.iter()
                                .filter_map(Value::as_f64)
                                .map(|f| f as u32)
                                .collect()
                        })
                        .unwrap_or_default();
                    compute_pass_push(
                        handle_of(recv),
                        ComputeCmd::SetBindGroup {
                            index: u32a(0, 0),
                            group: gidx,
                            dynamic_offsets,
                        },
                    )
                })
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPUComputePassEncoder", "dispatchWorkgroups") => Some(compute_pass_push(
            handle_of(recv),
            ComputeCmd::Dispatch {
                x: u32a(0, 1),
                y: u32a(1, 1),
                z: u32a(2, 1),
            },
        )),
        ("GPUComputePassEncoder", "end") => {
            let enc_idx = handle_of(recv);
            if let Some(e) = gpu_state().lock().unwrap().encoders.get_mut(enc_idx) {
                e.open_compute = None;
            }
            Some(Ok(Value::Null))
        }
        ("GPURenderPassEncoder", "setPipeline") => Some(
            obj(args.first())
                .map(handle_of)
                .map(|p| pass_push(handle_of(recv), PassCmd::SetPipeline(p)))
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPURenderPassEncoder", "setVertexBuffer") => Some(
            obj(args.get(1))
                .map(handle_of)
                .map(|b| pass_push(handle_of(recv), PassCmd::SetVertexBuffer { slot: u32a(0, 0), buffer: b }))
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPURenderPassEncoder", "setBindGroup") => Some(
            obj(args.get(1))
                .map(handle_of)
                .map(|gidx| pass_push(handle_of(recv), PassCmd::SetBindGroup { index: u32a(0, 0), group: gidx }))
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPURenderPassEncoder", "setIndexBuffer") => Some(
            obj(args.first())
                .map(handle_of)
                .map(|b| {
                    let u16 = args.get(1).and_then(Value::as_str).map(|s| s == "uint16").unwrap_or(false);
                    pass_push(handle_of(recv), PassCmd::SetIndexBuffer { buffer: b, u16 })
                })
                .unwrap_or(Ok(Value::Null)),
        ),
        ("GPURenderPassEncoder", "draw") => Some(pass_push(
            handle_of(recv),
            PassCmd::Draw { vertices: u32a(0, 0), instances: u32a(1, 1) },
        )),
        ("GPURenderPassEncoder", "drawIndexed") => Some(pass_push(
            handle_of(recv),
            PassCmd::DrawIndexed { indices: u32a(0, 0), instances: u32a(1, 1) },
        )),
        ("GPURenderPassEncoder", "end") => {
            let enc_idx = handle_of(recv);
            if let Some(e) = gpu_state().lock().unwrap().encoders.get_mut(enc_idx) {
                e.open_pass = None;
            }
            Some(Ok(Value::Null))
        }
        _ => None,
    }
}

/// The `navigator` global, with `gpu` present under the webgpu feature.
fn make_navigator_value() -> Value {
    let mut m = serde_json::Map::new();
    let mut gpu = serde_json::Map::new();
    gpu.insert("kind".into(), Value::String("GPUObject".into()));
    m.insert("gpu".into(), Value::Object(gpu));
    m.insert("userAgent".into(), Value::String("monster".into()));
    Value::Object(m)
}
